prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?allTaskCount)
  (COUNT(DISTINCT ?execTask) AS ?executableTaskCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL {
    ?start a bboExt:StartEvent ;
           tai:belongsTo ?choreo .

    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?execTask .
    ?execTask a bboExt:ChoreographyTask ;
              tai:belongsTo ?choreo .
  }

  OPTIONAL {
    # In case the graph uses StartEvent connected directly via SequenceFlow from start
    ?start a bboExt:StartEvent ;
           tai:belongsTo ?choreo .

    ?start (bbo:has_targetRef)+ ?execTask .
    ?execTask a bboExt:ChoreographyTask ;
              tai:belongsTo ?choreo .
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?allTaskCount)
  (COUNT(DISTINCT ?reachableTask) AS ?executableTaskCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .

  # Tasks reachable from any start event
  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachableTask .
  ?reachableTask a bboExt:ChoreographyTask ;
                  tai:belongsTo ?choreo .
}
GROUP BY ?model
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?start
  ?startName
  ?target
  ?targetType
  ?targetName
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo ;
         bbo:name ?startName .

  ?seq a bbo:SequenceFlow ;
       bbo:has_sourceRef ?start ;
       bbo:has_targetRef ?target .

  ?target a ?targetType .
  OPTIONAL { ?target bbo:name ?targetName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  (COUNT(DISTINCT ?start) AS ?startCount)
  (COUNT(DISTINCT ?task) AS ?taskCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
}
GROUP BY ?model
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?model
  ?modelName
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?start) AS ?startCount)
WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         ( tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" || tai:originalId "262d9e9b8c224d918fe800cd2a454ddf" ).
  OPTIONAL { ?model bbo:name ?modelName . }

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
}
GROUP BY ?model ?modelName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?model
  ?modelName
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?start) AS ?startCount)
WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }

  FILTER(
    (BOUND(?normId) && STR(?normId) = "262d9e9b8c224d918fe800cd2a454ddf") ||
    (BOUND(?origId) && STR(?origId) = "262d9e9b8c224d918fe800cd2a454ddf")
  )

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
}
GROUP BY ?model ?modelName
LIMIT 25
